mapper.select:
SELECT ue.int_id, ue.feed_id, ue.ref_id, e.id, e.title, e.link, e.updated, e.author, ue.unread, ue.marked, ue.published, ue.score, f.title AS feed_title, ts_rank(e.search_vector, websearch_to_tsquery('simple', #{keyword})) AS relevance FROM ttrss_user_entries ue INNER JOIN ttrss_entries e ON ue.ref_id = e.id INNER JOIN ttrss_feeds f ON ue.feed_id = f.id WHERE ue.owner_uid = #{userId} AND e.search_vector @@ websearch_to_tsquery('simple', #{keyword})
AND ue.feed_id = #{feedId}
AND f.cat_id = #{categoryId}
ORDER BY relevance DESC, ue.int_id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM ttrss_user_entries ue
INNER JOIN ttrss_entries e ON ue.ref_id = e.id
INNER JOIN ttrss_feeds f ON ue.feed_id = f.id
WHERE ue.owner_uid = #{userId}
  AND e.search_vector @@ websearch_to_tsquery('simple', #{keyword})

  AND ue.feed_id = #{feedId}


  AND f.cat_id = #{categoryId}
